+/// Measure the wall-clock time of a test suite execution.
+pub fn timed_suite<F, T>(f: F) -> (T, Duration)
+where
+    F: FnOnce() -> T,
+{
+    let start = Instant::now();
+    let result = f();
+    (result, start.elapsed())
+}
