+struct PerfReport {
+    generated_at: String,
+    operation_benchmarks: Vec<OperationBenchmark>,
+    hotspot_ranking: Vec<HotspotEntry>,
+    memory_notes: Vec<MemoryNote>,
+    isomorphism_check: IsomorphismCheck,
