+
+#[derive(Serialize)]
+struct OperationBenchmark {
+    operation: String,
+    size_desc: String,
+    n: usize,
+    iterations: usize,
+    median_ns: u128,
+    p95_ns: u128,
+    min_ns: u128,
+    max_ns: u128,
+    mean_ns: u128,
+}
+
+#[derive(Serialize)]
+struct HotspotEntry {
+    rank: usize,
+    operation: String,
+    size_desc: String,
+    median_ns: u128,
+    fraction_of_total: f64,
+}
+
+#[derive(Serialize)]
+struct MemoryNote {
+    operation: String,
+    size: String,
+    estimated_input_bytes: usize,
+    notes: String,
+}
+
+#[derive(Serialize)]
+struct IsomorphismCheck {
+    all_operations_pass: bool,
+    details: Vec<IsomorphismDetail>,
+}
+
+#[derive(Serialize)]
