+use serde::Serialize;
+use std::time::Instant;
+
+const WARMUP_ITERS: usize = 3;
+const BENCH_ITERS: usize = 30;
+
+type RootSolverFn = fn(fn(f64) -> f64, (f64, f64), RootOptions) -> Result<fsci_opt::RootResult, fsci_opt::OptError>;
+
+// ── Data structures ────────────────────────────────────────────────────
+
+#[derive(Serialize)]
