+    memory_notes: Vec<MemoryNote>,
+    isomorphism_check: IsomorphismCheck,
+}
+
+#[derive(Serialize)]
+struct OperationBenchmark {
+    operation: String,
+    input_desc: String,
+    iterations: usize,
+    median_ns: u128,
+    p95_ns: u128,
+    min_ns: u128,
+    max_ns: u128,
+    mean_ns: u128,
+}
+
+#[derive(Serialize)]
+struct HotspotEntry {
+    rank: usize,
