+        eprintln!(
+            "  #{}: {} ({}) — {:.0}ns ({:.1}%)",
+            h.rank, h.operation, h.input_desc, h.median_ns as f64, h.fraction_of_total * 100.0,
+        );
+    }
+    eprintln!();
+}

